import React from 'react';

import TabsItem from '../tabs-item';

import './tabs-item-list.css';

const TabsItemList = ({onItemChange, tabFilter, tabItems}) => {

    const renderTabsItem = tabItems.map((item) => {

        const isActive = tabFilter === item.name ? 'active' : '';

        return (
            <li key={item.name} onClick={() => onItemChange(item.name)} className={isActive}>
                <TabsItem label={item.label} />
            </li>
        );
    });

    return (
        <div className="tabs-item-list">
            <ul>
                {
                    renderTabsItem
                }
            </ul>
        </div>
    );
};

export default TabsItemList;