import React from 'react';

import Support from '../tabs-content/support';
import Security from '../tabs-content/security';
import Cloud from '../tabs-content/cloud';
import Equipment from '../tabs-content/equipment';

import './tabs-item-display.css';

const TabsItemDisplay = ({tabFilter}) => {

    const onTabItemDisplay = (tabFilter) => {

        switch(tabFilter){
            case "support":
                return <Support />;
            case "security":
                return <Security />;   
            case "cloud":
                return <Cloud />; 
            case "equipment":
                return <Equipment />;          
            default:
                return null;
        }

    };
    
    const tabView = onTabItemDisplay(tabFilter);

    return (
        <div className="tabs-item-display">
            {
                tabView
            }
        </div>
    );
};

export default TabsItemDisplay;