import React from 'react';

import Support from '../steps-content/support';
import Security from '../steps-content/security';
import Cloud from '../steps-content/cloud';
import Equipment from '../steps-content/equipment';

import './step-item-display.css';

const StepItemDisplay = ({stepFilter}) => {

    const onStepItemDisplay = (stepFilter) => {

        switch(stepFilter){
            case "support":
                return <Support />;
            case "security":
                return <Security />;   
            case "cloud":
                return <Cloud />; 
            case "equipment":
                return <Equipment />;          
            default:
                return null;
        }

    };
    
    const tabView = onStepItemDisplay(stepFilter);

    return (
        <div className="step-item-display">
            {
                tabView
            }
        </div>
    );
};

export default StepItemDisplay;