import React, {Component} from 'react';

import TabsItemDisplay from '../tabs-item-display';
import TabsItemList from '../tabs-item-list';

import StepItemList from '../step-item-list';
import StepItemDisplay from '../step-item-display';

import './app.css';

export default class App extends Component {

    state = {
        filter: 'support',
        items: [
            {
                id: 0,
                name: 'support',
                label: 'Support'
            },
            {
                id: 1,
                name: 'security',
                label: 'Security'
            },
            {
                id: 2,
                name: 'cloud',
                label: 'Cloud'
            },
            {
                id: 3,
                name: 'equipment',
                label: 'Equipment'
            },
        ]
    };

    onItemChange = (name) => {
        this.setState({
            filter: name
        });
    };

    onItemNext = () => {
        const itemLength = this.state.items.length;
        const idx = this.state.items.findIndex((item) => item.name === this.state.filter);
        if(idx+1 !== itemLength){
            const newFilter = this.state.items[idx+1].name;
            this.setState({
                filter: newFilter
            });
        }
    }

    onItemBack = () => {
        const idx = this.state.items.findIndex((item) => item.name === this.state.filter);
        if(idx !== 0){
            const newFilter = this.state.items[idx-1].name;
            this.setState({
                filter: newFilter
            });
        }
    }

    render() {

        const {filter, items} = this.state;

        return (
            <div className="app">
                <aside className="sidebar-left">
                    <StepItemDisplay stepFilter={filter}/>
                    <StepItemList onItemChange={this.onItemChange} onItemBack={this.onItemBack} onItemNext={this.onItemNext} stepFilter={filter} stepItem={items} />
                </aside>
                <aside className="sidebar-right">
                    <TabsItemList onItemChange={this.onItemChange} tabFilter={filter} tabItems={items} />
                    <TabsItemDisplay tabFilter={filter} />
                </aside>
            </div>
        );

    }

};