import React from 'react';

import './step-item-list.css';

const StepItemList = ({onItemChange, stepFilter, stepItem, onItemNext, onItemBack}) => {

    let activeItemLength = 0;
    stepItem.map((item) => {
        if(stepFilter === item.name){
            activeItemLength = item.id;
        }
        return true;
    });
     
    const renderItem = stepItem.map((item) => {

        const isActive = item.id <= activeItemLength ? 'active' : ''; 

        return (
            <li key={item.name} onClick={() => onItemChange(item.name)} className={isActive}>

            </li>
        );
    });

    const btnBack = stepFilter !== 'support' ? <button className="btn-back" onClick={() => onItemBack()}>Back</button> : null;
    const btnNext = stepFilter !== 'equipment' ? <button className="btn-next" onClick={() => onItemNext()}>Next</button> : null;

    return (
        <div className="step-item-list">
            <div className="btn-wrap">
                {btnBack}
            </div>          
            <ul className="pagination_steps">
			    {
                    renderItem
                }
		    </ul>
            <div className="btn-wrap">
                {btnNext}    
            </div>    
        </div>
    );
};

export default StepItemList;